package co.edu.elecciones.service; import co.edu.elecciones.repository.UserRepository; import org.springframework.security.core.userdetails.*; import org.springframework.stereotype.Service; import java.util.List; import org.springframework.security.core.authority.SimpleGrantedAuthority;
@Service public class UserDetailsServiceImpl implements UserDetailsService { private final UserRepository repo; public UserDetailsServiceImpl(UserRepository repo){this.repo=repo;} public UserDetails loadUserByUsername(String email){ var u=repo.findByEmail(email).orElseThrow(()->new UsernameNotFoundException(email)); return new User(u.email,u.password,u.active,true,true,true,List.of(new SimpleGrantedAuthority("ROLE_"+u.role.name()))); } }
